import java.util.*;

public class Solution {
    public static long solve(long n, long k) {
        if (k == 0) {
            return 0;
        }
        if (k == 1) {
            // Numbers with popcount-depth 1 are those whose binary representation has exactly 1 bit set
            // and is <= n
            long count = 0;
            for (long i = 1; i <= n; i *= 2) {
                if (i > n) break;
                count++;
            }
            return count;
        }

        // For k >= 2, we need to find numbers whose popcount-depth is exactly k
        // We can use BFS to find all numbers with popcount-depth exactly k
        // and count how many of them are <= n

        // BFS queue to store numbers and their current depth
        Queue<long[]> queue = new LinkedList<>();
        // Start with numbers that have popcount 1 (depth 1)
        for (long i = 1; i <= n; i *= 2) {
            if (i > n) break;
            queue.add(new long[]{i, 1});
        }

        // Set to track visited numbers to avoid processing the same number multiple times
        Set<Long> visited = new HashSet<>();
        for (long i = 1; i <= n; i *= 2) {
            if (i > n) break;
            visited.add(i);
        }

        long count = 0;

        while (!queue.isEmpty()) {
            long[] current = queue.poll();
            long num = current[0];
            int depth = current[1];

            if (depth == k) {
                count++;
                continue;
            }

            if (depth > k) {
                continue;
            }

            // Compute popcount of num
            long popCount = Long.bitCount(num);

            // If popCount is 0, it's already reached 0, which is not our case
            if (popCount == 0) {
                continue;
            }

            // If popCount is 1, then depth + 1 is the depth of the next number
            if (popCount == 1) {
                if (depth + 1 == k) {
                    count++;
                }
            } else {
                // For numbers with popCount > 1, we need to process their popcount values
                for (long i = 1; i <= popCount; i *= 2) {
                    if (i > popCount) break;
                    long nextNum = i;
                    if (visited.contains(nextNum)) {
                        continue;
                    }
                    visited.add(nextNum);
                    queue.add(new long[]{nextNum, depth + 1});
                }
            }
        }

        return count;
    }
}
