        return countNumbersWithPopcountDepth(n, k, memo);
    }

    private static long countNumbersWithPopcountDepth1(long n) {
        long count = 0;
        for (long i = 1; i <= n; i++) {
            long x = i;
            long depth = 0;
            while (x != 1) {
                x = Integer.bitCount((int) x);
                depth++;
            }
            if (depth == 1) {
                count++;
            }
        }
        return count;
    }

    private static long countNumbersWithPopcountDepth(long n, long k, Map<Long, Long> memo) {
        if (k == 0) {
            return 0;
        }
        if (k == 1) {
            return countNumbersWithPopcountDepth1(n);
        }
        if (memo.containsKey(n)) {
            return memo.get(n);
        }

        long count = 0;
        for (long i = 1; i <= n; i++) {
            long x = i;
            long depth = 0;
            while (x != 1) {
                x = Integer.bitCount((int) x);
                depth++;
            }
            if (depth == k) {
                count++;
            }
        }
        memo.put(n, count);
        return count;
    }
}
